import { createSlice } from '@reduxjs/toolkit';

// ============================================================================
// HELPER FUNCTIONS (Crash-Proof Local Storage Handlers)
// ============================================================================

// Safely load from local storage to prevent the JSON.parse crash
const loadCartFromStorage = () => {
  try {
    const savedCart = localStorage.getItem('cartItems');
    if (savedCart) {
      return JSON.parse(savedCart);
    }
    return [];
  } catch (error) {
    console.error("Critical: Corrupted data in localStorage. Resetting cart.", error);
    return [];
  }
};

// Safely save to local storage
const saveCartToStorage = (items) => {
  try {
    localStorage.setItem('cartItems', JSON.stringify(items));
  } catch (error) {
    console.error("Failed to save cart to localStorage.", error);
  }
};

// ============================================================================
// INITIAL STATE
// ============================================================================

const initialState = {
  items: loadCartFromStorage(),
  reservation: null, // Added this back for your reservation logic
};

// ============================================================================
// REDUX SLICE
// ============================================================================

const cartSlice = createSlice({
  name: 'cart',
  initialState,
  reducers: {
    // Add item or increase quantity if it already exists
    addToCart: (state, action) => {
      const newItem = action.payload;
      const existingItem = state.items.find((item) => item.id === newItem.id);

      if (existingItem) {
        existingItem.quantity = (existingItem.quantity || 1) + (newItem.quantity || 1);
      } else {
        state.items.push({ ...newItem, quantity: newItem.quantity || 1 });
      }

      saveCartToStorage(state.items);
    },

    // Completely remove an item by ID
    removeFromCart: (state, action) => {
      const idToRemove = action.payload;
      state.items = state.items.filter((item) => item.id !== idToRemove);

      saveCartToStorage(state.items);
    },

    // Adjust the exact quantity of an item (+ / - buttons)
    updateQuantity: (state, action) => {
      const { id, quantity } = action.payload;
      const existingItem = state.items.find((item) => item.id === id);

      if (existingItem) {
        if (quantity <= 0) {
          state.items = state.items.filter((item) => item.id !== id);
        } else {
          existingItem.quantity = quantity;
        }

        saveCartToStorage(state.items);
      }
    },

    // Empty the entire cart
    clearCart: (state) => {
      state.items = [];
      localStorage.removeItem('cartItems');
    },

    // RESTORED: Your missing reservation logic!
    setReservation: (state, action) => {
      state.reservation = action.payload;
    },
  },
});

// Make sure setReservation is included in the exports here!
export const { addToCart, removeFromCart, updateQuantity, clearCart, setReservation } = cartSlice.actions;

export default cartSlice.reducer;
